# Shape hierarchy module - demonstrates abstract classes, interfaces, and inheritance

interface IScalable:
    def scale(self, factor: float) -> None: ...

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def area(self) -> float: ...

    @abstract
    def perimeter(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return self.name + " (generic shape)"

class Circle(Shape, IScalable):
    radius: float

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        return "Circle with radius " + str(self.radius)

    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

class Rectangle(Shape, IScalable):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle")
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return "Rectangle " + str(self.width) + "x" + str(self.height)

    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor
